VALUES
  ('elementary-10ced7e2-moex-00741', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '關於刑法第19條第3項之規定，下列敘述何者錯誤？', '["學理上稱之為原因自由行為", "本項須行為人在實際實行犯罪時具備完全行為責任能力狀況", "現行立法模式，在學理上有稱為例外模式", "本項須行為人因故意或過失自行招致無責任能力或限制責任能力狀況"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00742', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列何者是憲法最高性的直接展現？', '["行政院之施政不得牴觸立法院三讀通過，總統公布之法律", "法院之判決，不得不適用法規或適用不當", "立法院通過之法律，不得牴觸憲法", "行政機關之管轄權，不得違反其組織法規，非依法規不得設定或變更"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00743', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依司法院大法官解釋，有關自由民主憲政秩序，下列敘述何者錯誤？', '["係指憲法中具有本質之重要性而為規範秩序存立之基礎者", "憲法增修條文如與憲法中具有本質重要性之規範相衝突，依後法優於前法之原則，增修條文之效力優先", "其內涵包括憲法規定之民主共和國原則與國民主權原則", "凡憲法設置之機關，均有遵守自由民主憲政秩序之義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00744', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '依憲法及公民投票法規定，有關我國公民投票制度，下列敘述何者正確？', '["是憲法上依法行政原則的實現", "因為是對事、而非對人的投票，所以普通、平等、直接之投票方法不適用", "現行制度不只有全國性，也有地方性之公民投票", "為確實監督國家政策之落實，得針對預算與人事事項提案發起公民投票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00745', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關比例原則之敘述，下列何者錯誤？', '["須採取之方法應有助於目的之達成", "多種同樣達成目的之方法中，須採取對人民權益損害最少者", "須採取之方法所造成之損害不得與欲達成目的之利益顯失均衡", "一行為違反數行政法上義務，應採取最輕之處罰規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00746', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列事項，何者不適用我國行政程序法之程序規定？', '["外交部與外國之建交行為", "撤銷進出口廠商營業登記之行為", "廢止土地徵收之行為", "再生能源發電設備生產電能躉購費率之審定行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00747', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '下列關於執行上級命令之行為不罰之敘述，何者錯誤？', '["明知上級公務員之命令為違法而執行之，不得阻卻違法", "以下達之命令為下級公務員之職務範圍內，始得主張阻卻違法", "下級公務員執行不符法定程式之命令，亦得阻卻違法", "命令之形式雖不以書面為限，但仍以具備法定程式為必要"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00748', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '人民申請換發汽車行車執照，卻遭公路監理機關以違規罰鍰尚未繳清為由，拒絕換發行車執照。此舉可 能違反下列何種行政上之一般法律原則？', '["不當聯結禁止原則", "比例原則", "誠實信用原則", "信賴保護原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00749', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關損失補償之敘述，下列何者錯誤？', '["因公益而特別犧牲財產上之利益，國家應依法律規定辦理補償", "損失補償是針對國家的合法行為而干預人民之財產權所生之填補措施", "現行法下，行政徵收不以公用之目的為限", "基於平等原則，只要國家對財產權有所限制，即應給予補償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00750', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-111-55d283b0', 'sub-elementary-10ced7e2-04', NULL, 'single_choice', '有關公共設施國家賠償責任的敘述，下列何者錯誤？', '["須賠償義務機關有故意或過失，始成立國家賠償責任", "公共設施委託民間團體管理，因管理欠缺導致人民人身自由或財產受有損害，國家亦負賠償責任", "於開放山域的自然公物，經管理機關對公物為適當的警告或標示，人民仍從事冒險或具危險性活動而 受有損害，國家不負賠償責任", "建築中的公共設施未開放公用，即非屬公共設施"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:48+00:00", "source_pdf_sha1": "f6900110398a", "answer_pdf_sha1": "55a33c58e1da", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
